fixed_code:
trait Calculator {
    fn divide(&self, a: i32, b: i32) -> Option<i32>;
}

struct IntCalculator;
impl Calculator for IntCalculator {
    fn divide(&self, a: i32, b: i32) -> Option<i32> {
        if b == 0 { None } else { Some(a / b) }
    }
}

fn main() {
    let calc = IntCalculator;
    match calc.divide(10, 0) {
        Some(result) => println!("{}", result),
        None => println!("Division by zero error")
    }
}
